#Defining all functions

@logging_to_appins
def read_file(file_path):
    try:
        if file_path.endswith(".csv"):
            return spark.read.option("header", True).csv(file_path)
        elif file_path.endswith(".xlsx"):
            job_id = mssparkutils.env.getJobId()
            mount_path = f"/synfs/{job_id}/temp_raw/{file_path.split('/')[-1]}"
            mount_storage(file_path)
            df = pd.read_excel(mount_path, dtype=str)
            unmount_storage()
            return spark.createDataFrame(df)
        else:
            raise Exception("Unsupported file format")
    except Exception as e:
        logError(f"Failed to load file {file_path}: {e}")
        return None

def clean_column_names(df):
    cols = [re.sub(r"[^a-zA-Z0-9_]+", "", c).strip('_') for c in df.columns]
    deduped = []
    for i, c in enumerate(cols):
        count = cols[:i].count(c)
        deduped.append(f"{c}{count + 1}" if count else c)
    return df.toDF(*deduped)

# Reorder dataframe columns to bring additional metadata columns to the front
def reorder_columns(df):
    """Reorders the columns so that metadata columns come first."""
    try:
        metadata_cols = ["ingested_datetime", "expected_from", "expected_to"]
        remaining_cols = [col for col in df.columns if col not in metadata_cols]
        return df.select(metadata_cols + remaining_cols)
    except Exception as e:
        print(f"Error reordering columns: {e}")
        return df

@logging_to_appins
def create_table_if_not_exists(path, table_name, schema_path):
    try:
        if not DeltaTable.isDeltaTable(spark, path):
            schema_json = json.loads("".join([r.value for r in spark.read.text(schema_path).collect()]))
            schema_str = ", ".join([f"{f['name']} {f['type']}" for f in schema_json["fields"]])
            spark.sql(f"CREATE TABLE IF NOT EXISTS {table_name} ({schema_str}) USING DELTA LOCATION '{path}'")
    except Exception as e:
        logError(f"Error creating table {table_name}: {e}")

# Create File list
def list_files(folder_path):
    """Returns a list of file names in the given folder."""
    try:
        return [f.name for f in mssparkutils.fs.ls(folder_path) if not f.isDir]
    except Exception as e:
        print(f"Error listing files in {folder_path}: {e}")
        return []

# Clean all column names from the souce file dataframe by removing special character like ".",":" " " 
def clean_column_names(df):
    """Removes special characters from column names."""
    try:
        df = df.toDF(*[re.sub(r"[^a-zA-Z0-9_]", "", c.replace(" ","")) for c in df.columns])

        df = df.select([col for col in df.columns if not col.startswith('Unnamed')])
        
        # remove all records if all columns having Null values
        df = df.dropna(how="all")

        # Identify columns that are already DateType
        date_columns = [field.name for field in df.schema.fields if isinstance(field.dataType, TimestampType)]

        #print("Detected Date Columns:", date_columns)

        # If PersNo or StaffNumber exists, add leading zeros for values having 6 characters lengths
        for column in ["PersNo", "StaffNumber"]: 
            if column in df.columns: 
                df = df.withColumn(column, when(length(col(column)) == 6, lpad(col(column), 8, "0")).otherwise(col(column)))

        return df
        
    except Exception as e:
        print(f"Error cleaning column names: {e}")
        return df

# Add additional metadata columns for Standardised_db Lakehouse database
def add_metadata_columns(df):
    """Adds standard metadata columns to the DataFrame."""
    try:
        return (df
            .withColumn("ingested_datetime", lit(datetime.now()).cast(TimestampType()))
            .withColumn("expected_from", lit((datetime.now() - timedelta(days=1)).strftime('%Y-%m-%d')).cast(TimestampType()))
            .withColumn("expected_to", lit(datetime.now().strftime('%Y-%m-%d')).cast(TimestampType()))
        )
    except Exception as e:
        print(f"Error adding metadata columns: {e}")
        return df

def add_loggingdata_columns(df,source_filename_start):
    """Adds standard metadata columns to the DataFrame."""
    try:
        return (df
            .withColumn("ingested_by_process_name", lit('raw-to-std'))
            .withColumn("input_file", input_file_name())
            .withColumn("modified_datetime", current_timestamp())
            .withColumn("modified_by_process_name", lit('raw-to-std'))
            .withColumn("entity_name", lit(source_filename_start))
            .withColumn("file_ID", sha2(concat(lit(input_file_name()), current_timestamp().cast("string")), 256))
        )
    except Exception as e:
        print(f"Error adding metadata columns: {e}")
        return df


