        return df

# Load file dataframe in preparedness to load data into Standerdised_DB database Delta Table.
def load_file(file_path, file_type):
    """Reads a file into a PySpark DataFrame based on file type."""
    try:
        if file_type == "xlsx":
            return spark.read.format("com.crealytics.spark.excel").option("header", "true").option("inferSchema", "false").load(file_path)
        elif file_type == "csv":
            return spark.read.format("csv").option("header", "true").option("inferSchema", "false").load(file_path)
    except Exception as e:
        print(f"Error loading file {file_path}: {e}")
        return None

def process_file(original_filename, file_type, folder_path, delta_base_path, database_name):
    """Handles loading, cleaning, and writing data to Delta Tables."""
    try:
        if Param_File_Load_Type.strip().lower() != "none":
            table_name = re.sub(r'\d+', '', original_filename).replace(f".{file_type}", f"{Param_File_Load_Type}").lower()
        else:
            table_name = re.sub(r'\d+', '', original_filename).replace(f".{file_type}","").lower()
        
        delta_table_path = f"{delta_base_path}/{table_name}"
        full_table_name = f"{database_name}.{table_name}"
        
        file_path = f"{folder_path}/{original_filename}"
        
        df = load_file(file_path, file_type)
        if df is None:
            return
        df = clean_column_names(df)
        file_record_count = df.count()        
        df = add_metadata_columns(df)
        df = reorder_columns(df)
        
        if DeltaTable.isDeltaTable(spark, delta_table_path):
            print(f"Delta Table exists for {full_table_name}. Loading data from {original_filename}")
            target_df = spark.read.format("delta").load(delta_table_path)
            target_record_count = target_df.count()
        else:
            print(f"Delta Table does NOT exist for {full_table_name}. Creating table using {original_filename}")
            target_record_count = 0
            schema_df = spark.read.option("multiline", "true").json(json_file_path)
            schema_data = schema_df.collect()
            
            if schema_data:
                schema_tables = schema_data[0].asDict().get("table_name", {})
                if table_name in schema_tables:
                    columns = schema_tables[table_name]["columns"]
                    schema_str = ", ".join([f"{col['name']} {col['type']}" for col in columns])
                    spark.sql(f"""CREATE TABLE IF NOT EXISTS {full_table_name} ({schema_str}) USING DELTA LOCATION '{delta_table_path}'""")
                else:
                    print(f"Rohit table_name : {table_name}")
                    print(f"Schema not found for {table_name} in create_schema.json")
                    return
        
        df.write.format("delta").mode("overwrite").save(delta_table_path)
        print(f"Data successfully loaded for {table_name} using {original_filename}.")
        print(f"File Record Count: {file_record_count}, Target Table Record Count: {target_record_count}")
    except Exception as e:
        print(f"Error processing file {original_filename}: {e}")

# Main Execution
try:
    file_list = list_files(odw_raw_folder_path)
    if not file_list:
        print(f"No files found in the folder: {odw_raw_folder_path}")
    else:
        for file_type in ["xlsx", "csv"]:
            files = [f for f in file_list if f.lower().endswith(f".{file_type}")]
            for file in files:
                process_file(file, file_type, odw_raw_folder_path, delta_table_base_path, database_name)
except Exception as e:
    print(f"Unexpected error in main execution: {e}")
